INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Full MQTT 5.0 protocol support$q$, $q$Implements MQTT 3.1, 3.1.1, and 5.0, including MQTT over QUIC, TLS/SSL, and WebSocket transports for secure, flexible device connectivity.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Massive horizontal scalability$q$, $q$Erlang/OTP-based clustering architecture benchmarked to support up to 100 million concurrent connections across a single cluster.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Built-in rule engine$q$, $q$Filters, transforms, and routes MQTT messages to external systems using a lightweight SQL-like rule syntax without custom code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$40+ data integrations$q$, $q$Pre-built connectors to Kafka, Kinesis, PostgreSQL, MySQL, Redis, Elasticsearch, InfluxDB, and major cloud data warehouses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Device authentication and ACLs$q$, $q$Supports username/password, JWT, X.509 certificate, and PSK authentication with fine-grained topic-level access control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Real-time monitoring dashboard$q$, $q$Web-based dashboard for observing connections, topics, message throughput, and cluster health.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Flexible deployment models$q$, $q$Runs as a single Docker container, a self-managed cluster on-prem or at the edge, or a fully managed cloud service.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$MQTT over QUIC$q$, $q$Reduces connection latency and improves reliability on unstable networks compared to MQTT over TCP.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Extremely high connection scalability, proven in large industrial and automotive deployments$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Free to self-host for development and single-node production use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Rich library of native data integrations for streaming device data into analytics and AI systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Flexible deployment across self-hosted, BYOC, and fully managed cloud options$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Business Source License requires a paid license for clustered production deployments$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Erlang-based codebase has a steeper learning curve for teams wanting to contribute or deeply customize$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Cloud Dedicated Flex and BYOC pricing can become expensive at high connection/message volumes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Enterprise pricing is custom and not transparently published$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Is EMQX free to use?$q$, $q$Yes. EMQX is free to download and self-host for development, testing, and single-node production deployments under the Business Source License 1.1. A commercial license is required for multi-node clustering in production or for embedding it in a commercially distributed product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$What license does EMQX use?$q$, $q$EMQX moved from Apache License 2.0 to the Business Source License (BSL) 1.1 starting with version 5.9. Each version automatically converts back to Apache 2.0 four years after release.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$How many connections can EMQX handle?$q$, $q$EMQX has been benchmarked supporting up to 100 million concurrent MQTT connections on a single 23-node cluster, making it one of the most scalable MQTT brokers available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$What is EMQX Cloud Serverless?$q$, $q$Serverless is a fully managed, pay-as-you-go EMQX offering with a free monthly quota covering up to 1,000 connections and limited sessions, traffic, and rule actions before usage-based billing applies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Who uses EMQX?$q$, $q$EMQX is used by IoT platform teams, industrial manufacturers, automotive companies building connected-vehicle platforms, and telecom operators, including BMW, Volkswagen, Geely, Ericsson, HPE, and TSMC.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$How does EMQX compare to Mosquitto?$q$, $q$Eclipse Mosquitto is a lightweight, single-node MQTT broker well suited to small deployments, while EMQX is designed for horizontal clustering and much higher connection volumes, along with built-in data integrations and a management dashboard.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Industrial IoT data ingestion$q$, $q$Manufacturers use EMQX to collect sensor and equipment telemetry from factory floors and route it into analytics or AI systems in real time.$q$, $q$Industrial IoT and manufacturing engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Connected vehicle platforms$q$, $q$Automotive companies use EMQX to maintain persistent MQTT connections with millions of vehicles for telemetry, over-the-air updates, and remote diagnostics.$q$, $q$Automotive and software-defined vehicle engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Consumer IoT device fleets$q$, $q$Smart home, wearable, and appliance makers use EMQX to manage device connectivity, command delivery, and firmware update distribution at scale.$q$, $q$Consumer IoT product and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full MQTT broker functionality","Single-node production use permitted","Community support via GitHub and forums","Business Source License 1.1"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Cloud Serverless$q$, $q$$0 to start, pay-as-you-go beyond free quota$q$, $q$Monthly$q$, NULL, $q$["Up to 1,000 free connections","Free monthly quota on sessions, traffic, and rule actions","TLS/SSL encryption","Basic monitoring and 8/5 support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Cloud Dedicated Flex$q$, $q$From $234/month$q$, $q$Monthly$q$, NULL, $q$["Dedicated, isolated cluster","VPC peering and private link","40+ data integrations","99.99% uptime SLA","24/7 premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Cloud BYOC$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Deployed inside your own VPC","EMQ manages upgrades and observability","Data stays within your cloud account"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$Enterprise (Self-Managed)$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Deploy anywhere: on-prem, edge, or cloud","Custom plugins and extensions","Message size up to 256 MB","Professional services and priority feature requests"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$EMQX is an open-source MQTT message broker built to connect and process real-time data streams from IoT devices, industrial equipment, and connected vehicles at massive scale. Originally released in 2013 and now maintained by EMQ Technologies, it has grown from a lightweight Erlang-based broker into what the company calls a unified MQTT platform for AI and IoT data streaming.$q$, $q$The project is one of the most widely deployed MQTT implementations in the world, with more than 10,000 GitHub stars, over 20 million downloads, and production use by more than 1,500 enterprises including BMW, Volkswagen, Ericsson, HPE, and TSMC.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$EMQX supports the full MQTT 3.1/3.1.1/5.0 specification plus MQTT over QUIC, TLS/SSL, and WebSocket transport, and can cluster horizontally to handle up to 100 million concurrent connections in benchmark testing.$q$, $q$A built-in rule engine and more than 40 pre-built data integrations let teams route device data directly into Kafka, PostgreSQL, Elasticsearch, cloud data warehouses, and AI pipelines without custom bridge code, alongside authentication, access control lists, and a real-time monitoring dashboard.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$EMQX is free to self-host for development, testing, and single-node production use under its Business Source License 1.1 (each version reverts to Apache 2.0 after four years). Multi-node clustering in production requires a commercial license.$q$, $q$For managed hosting, EMQX Cloud offers a pay-as-you-go Serverless plan with a free monthly quota, a Dedicated Flex plan starting at $234/month for an isolated cluster with a 99.99% SLA, a Bring-Your-Own-Cloud plan, and a custom-priced self-managed Enterprise tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5acefb5-8215-460f-9c6a-0a3d1e382f7e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Visual flow builder$q$, $q$Canvas-based automation designer for building multi-step customer journeys with triggers, conditions, and actions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Behavior-based email triggers$q$, $q$Sends emails based on in-app usage events, trial status, and custom behavioral data rather than only marketing actions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Native billing integrations$q$, $q$Connects directly to Stripe and Chargebee so automations can respond to upgrades, downgrades, failed payments, and cancellations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$CRM and data integrations$q$, $q$Premium-tier integrations with HubSpot, Salesforce, and Segment.com sync customer data across the marketing and sales stack.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Advanced segmentation$q$, $q$Builds dynamic contact segments from behavioral, demographic, and custom field data for targeted campaigns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Transactional email sending$q$, $q$Premium plans can send transactional messages such as receipts and password resets through the same platform as marketing email.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$API and webhooks$q$, $q$Documented API and webhook support let developers trigger flows from custom events anywhere in a product.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Free email verification$q$, $q$Built-in list verification helps maintain sender reputation and deliverability at no extra cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Purpose-built for B2B SaaS lifecycle marketing rather than generic email blasting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Native Stripe and Chargebee integrations tie automations directly to billing events$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Unlimited flows and team members on every paid plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$More affordable than enterprise suites like HubSpot for SaaS-specific use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$No permanent free plan, only a 14-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$HubSpot and Salesforce integrations are limited to the higher-priced Premium tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Pricing scales with subscriber count, which can add up for larger lists$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Smaller integration ecosystem than larger competitors like ActiveCampaign or Customer.io$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$What is Encharge used for?$q$, $q$Encharge is used by B2B SaaS companies to automate behavior-based email marketing, including trial onboarding, conversion nurture sequences, churn prevention, and customer lifecycle segmentation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$How much does Encharge cost?$q$, $q$Encharge's Growth plan starts at $99/month (or $79/month billed annually) for up to 2,000 subscribers, and the Premium plan starts at $159/month (or $129/month billed annually) for the same subscriber count. Custom Enterprise pricing is available above 50,000 subscribers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Does Encharge have a free plan?$q$, $q$No. Encharge does not offer a permanent free tier, but every paid plan includes a 14-day free trial.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Who founded Encharge?$q$, $q$Encharge was founded in 2018 by Kalo Yankulov and Slav Ivanov and is headquartered in Sofia, Bulgaria.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$What integrations does Encharge support?$q$, $q$Encharge integrates natively with Stripe, Chargebee, Segment, Zapier, and, on the Premium plan, HubSpot, Salesforce, WooCommerce, and Shopify, alongside a general API and webhooks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$What are the main alternatives to Encharge?$q$, $q$The closest competitors are Customer.io and ActiveCampaign, both of which offer similar flow-based, behavior-triggered marketing automation for SaaS and e-commerce companies.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$SaaS trial-to-paid conversion$q$, $q$Automate nurture sequences triggered by trial sign-up, feature usage, and trial expiration to increase conversion to paid plans.$q$, $q$B2B SaaS growth and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Behavior-based onboarding$q$, $q$Send onboarding emails based on specific in-app actions or inaction, guiding new users toward activation milestones.$q$, $q$Product marketers and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Churn prevention and win-back$q$, $q$Trigger flows off Stripe or Chargebee events like failed payments or cancellations to attempt recovery before churn is finalized.$q$, $q$SaaS revenue and retention teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Growth$q$, $q$$99/month (monthly) or $79/month (annual)$q$, $q$Monthly or Annual$q$, NULL, $q$["Up to 2,000 subscribers","Unlimited flows and team members","Flow builder and advanced segmentation","Behavior-based email","Webhooks and Zapier/Stripe/Chargebee integrations","Free email verification","Live chat support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Premium$q$, $q$$159/month (monthly) or $129/month (annual)$q$, $q$Monthly or Annual$q$, NULL, $q$["Up to 2,000 subscribers","All Growth features","HubSpot and Salesforce integrations","Segment.com, WooCommerce, and Shopify integrations","Transactional emails and API events","Custom objects","Live chat and Slack support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["50,000+ subscribers","All Premium features","Dedicated account manager","Free onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Encharge is a marketing automation platform built specifically for B2B SaaS companies, combining a visual flow builder with behavior-based email triggers so teams can automate onboarding, trial conversion, and churn-prevention sequences based on how customers actually use their product.$q$, $q$Founded in 2018 in Sofia, Bulgaria by Kalo Yankulov and Slav Ivanov, Encharge has grown as a bootstrapped company with a small team, focusing narrowly on SaaS lifecycle marketing rather than trying to compete as a broad, all-purpose marketing suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's canvas-based flow builder lets teams chain together triggers, conditions, and actions to build multi-step automations, with native integrations into Stripe, Chargebee, Segment, HubSpot, Salesforce, and Zapier so flows can react to billing events and product usage, not just email opens.$q$, $q$Additional capabilities include advanced contact segmentation, transactional email sending on higher tiers, webhooks and a documented API for custom event tracking, and free built-in email verification to protect sender reputation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Encharge prices by number of subscribers on two core tiers: Growth starts at $99/month (or $79/month billed annually) for up to 2,000 subscribers, and Premium starts at $159/month (or $129/month billed annually) for the same subscriber baseline with deeper CRM and e-commerce integrations.$q$, $q$Both tiers scale in price with list size, and overage emails cost $100 per additional 100,000 sends. A custom-priced Enterprise tier is available for lists over 50,000 subscribers, and every plan includes a 14-day free trial rather than a permanent free tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6af548d4-ec3e-4639-a001-7473d57669b6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Client-side end-to-end encryption$q$, $q$Notes are encrypted in the browser with AES-GCM (256-bit key, PBKDF2 derivation) before ever reaching the server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Zero-knowledge server design$q$, $q$The server stores only encrypted ciphertext and never has access to decryption keys or plaintext content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Self-destructing notes$q$, $q$Notes can be configured to delete permanently after being read once or after a set expiration time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Password protection$q$, $q$Senders can add an additional password requirement on top of the encrypted link for extra security.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$File attachments$q$, $q$Supports securely attaching and sharing files alongside encrypted note content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Command-line interface$q$, $q$A CLI tool lets developers create and share encrypted notes directly from the terminal.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Self-hosting via Docker$q$, $q$An official Docker image makes it straightforward to run a private, self-hosted Enclosed instance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Open-source codebase$q$, $q$Released under Apache License 2.0 with the full source available on GitHub for auditing or modification.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Completely free with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Genuine zero-knowledge, client-side encryption architecture$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Simple, minimalist interface with low learning curve$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Self-hostable via Docker for full data control$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Maintained by a small independent project rather than a company, with no formal SLA or support guarantees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$No built-in team or organization management features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Lacks integrations found in commercial secret-sharing tools (e.g., enterprise SSO)$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Relies on the recipient understanding the link expires or self-destructs, which can cause accidental data loss if misunderstood$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Is Enclosed free to use?$q$, $q$Yes. Enclosed is completely free at the public enclosed.cc instance, and self-hosting the open-source Docker image is also free aside from your own infrastructure costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$How does Enclosed keep notes secure?$q$, $q$Enclosed encrypts notes in the sender's browser using AES-GCM with a 256-bit key derived via PBKDF2 before sending anything to the server, so the server never has access to the plaintext content or decryption key.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Can I self-host Enclosed?$q$, $q$Yes. Enclosed is open source under the Apache License 2.0 and publishes an official Docker image (corentinth/enclosed) for self-hosting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Who built Enclosed?$q$, $q$Enclosed was built by French software engineer Corentin Thomasset and launched publicly on Product Hunt in October 2024.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Does Enclosed have a CLI?$q$, $q$Yes. Enclosed includes a command-line interface so developers can create and share encrypted notes directly from a terminal.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$What are alternatives to Enclosed?$q$, $q$Similar self-destructing, encrypted note-sharing tools include PrivNote, Yopass, and OneTimeSecret.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Sharing credentials securely$q$, $q$Send passwords, API keys, or access tokens through a self-destructing encrypted link instead of plaintext chat or email.$q$, $q$Developers and IT administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$One-time confidential messages$q$, $q$Share sensitive personal or business information that should not persist in an inbox or chat history.$q$, $q$Privacy-conscious individuals and remote teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Self-hosted internal secret sharing$q$, $q$Run a private Enclosed instance inside a company network for internal secret sharing without relying on third-party services.$q$, $q$Security and DevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Hosted (enclosed.cc)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Client-side encrypted notes","Password protection and expiration settings","File attachments","No account required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$Self-Hosted$q$, $q$Free (open source)$q$, $q$N/A$q$, NULL, $q$["Full control over data and infrastructure","Official Docker image","Apache 2.0 licensed source code","Command-line interface support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Enclosed is a free, open-source web app for sending private, end-to-end encrypted notes and files that self-destruct after being read or after a set expiration time. It was built by French engineer Corentin Thomasset and launched publicly on Product Hunt in October 2024.$q$, $q$The tool is designed for sharing sensitive one-time information such as passwords or API keys through a link rather than plaintext email or chat, with encryption happening entirely in the sender's browser so the server never has access to the content.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Notes are encrypted client-side with AES-GCM using a 256-bit key derived via PBKDF2, giving Enclosed a genuine zero-knowledge architecture where even the server operator cannot read note contents.$q$, $q$Senders can optionally password-protect a note, set an expiration time, attach files, or trigger self-destruction immediately after the first read, and a command-line interface lets developers create notes directly from a terminal.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Enclosed is entirely free to use at the public enclosed.cc instance, with no paid tiers or subscription plans.$q$, $q$The source code is released under the Apache License 2.0 and published on GitHub with an official Docker image, so anyone can self-host their own private instance at the cost of their own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b886551b-23de-40d7-8f48-7bb6d59c286b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Infrastructure from code$q$, $q$Declare databases, Pub/Sub topics, cron jobs, and caches as typed objects in application code; Encore provisions matching cloud resources automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$TypeScript and Go support$q$, $q$Write full backend services with end-to-end type safety in either TypeScript or Go.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Local development environment$q$, $q$Runs a real local Postgres instance, distributed tracing, and an API explorer with zero cloud account required.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Deploy to your own cloud account$q$, $q$Production deployments provision AWS or GCP resources directly inside the customer's own cloud account, avoiding vendor lock-in.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Preview environments per pull request$q$, $q$Pro tier automatically spins up isolated preview environments for every pull request.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Distributed tracing and observability$q$, $q$Built-in tracing dashboards for both local development and production, with Datadog and Grafana integrations on paid tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Automatic architecture diagrams$q$, $q$Generates a service catalog and architecture diagram directly from application code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Standard container export$q$, $q$The `encore build docker` command generates a standard Docker container, letting teams migrate away from Encore Cloud if needed.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Open-source core framework and local dev tooling, usable entirely for free$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Deploys infrastructure directly into the customer's own AWS/GCP account, avoiding lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Automated infrastructure provisioning removes significant DevOps boilerplate$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Founders' backend engineering background at Spotify informs strong developer experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Paid Pro tier combines a per-member fee with separate per-environment and per-resource charges, which can be hard to predict at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Currently limited to TypeScript and Go, unlike broader-language platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Smaller ecosystem and community than long-established frameworks$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Best cost and workflow benefits require committing to Encore's opinionated project structure$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Is Encore free to use?$q$, $q$The Encore framework and local development tooling are free and fully open source. The managed Encore Cloud platform has a free tier for hobby projects, with a paid Pro tier starting at $49 per member per month plus environment and resource fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$What languages does Encore support?$q$, $q$Encore currently supports TypeScript and Go for building backend services.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Where does Encore deploy my application?$q$, $q$Encore Cloud provisions and deploys infrastructure directly inside your own AWS or GCP account, rather than hosting it on Encore's own infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Who founded Encore?$q$, $q$Encore was founded in 2020 in Stockholm, Sweden by André Eriksson and Marcus Kohlberg, both former Spotify engineers, and has raised a $3 million seed round led by Crane Venture Partners.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$How is Encore different from Supabase?$q$, $q$Supabase is a backend-as-a-service platform where you define a database schema and it auto-generates APIs; Encore has you write full backend services in code and automatically provisions matching infrastructure inside your own cloud account.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Can I avoid vendor lock-in with Encore?$q$, $q$Yes. The `encore build docker` command generates a standard Docker container from an Encore application, which can be deployed and run outside of Encore Cloud.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Startup backend infrastructure$q$, $q$Early-stage teams use Encore to skip manual DevOps setup and get a production-ready backend with databases and Pub/Sub provisioned automatically.$q$, $q$Startup engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Multi-service backend systems$q$, $q$Teams building distributed systems use Encore's service catalog and architecture diagrams to keep complex microservice architectures understandable.$q$, $q$Backend and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Cloud-account-owned deployments$q$, $q$Companies with compliance or data residency requirements use Encore to deploy backend infrastructure inside their own AWS or GCP account rather than a third party's.$q$, $q$Regulated industries and enterprise engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Local development with automated infrastructure","2 free development environments on Encore Cloud","1M distributed tracing events/month","7-day logs and trace retention","Secrets management","CI/CD and automated testing","Community Discord support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Pro$q$, $q$From $49/member/month + $99/month per environment + ~$2.50/month per resource$q$, $q$Monthly$q$, NULL, $q$["Unlimited free dev environments","20M tracing events/month (then $1.20 per additional 1M)","30-day logs and trace retention","Preview environments per pull request","Custom domains","Web Application Firewall (Cloudflare)","Datadog/Grafana integrations","Private Slack support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Custom concurrent builds","Least-privilege IAM management","Self-hosted preview environments","Custom RBAC and network security rules","SOC 2 compliance assistance","Dedicated Technical Account Manager","Custom uptime SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Encore is an open-source backend framework for TypeScript and Go, paired with a cloud platform (Encore Cloud) that automatically provisions the infrastructure a backend needs directly inside a developer's own AWS or GCP account.$q$, $q$Founded in 2020 in Stockholm, Sweden by ex-Spotify engineers André Eriksson and Marcus Kohlberg, Encore raised a $3 million seed round led by Crane Venture Partners and has positioned itself as an alternative to both schema-first backend-as-a-service platforms and manual infrastructure-as-code tooling.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Developers declare infrastructure such as databases, Pub/Sub topics, cron jobs, and storage buckets as typed objects directly in application code, and Encore's tooling provisions matching resources automatically, both locally for development and in production inside the customer's own cloud account.$q$, $q$Local development tooling, including infrastructure emulation, distributed tracing, and an API explorer, has been fully open source since May 2024 and requires no Encore account, while the managed Encore Cloud platform adds preview environments, production observability, and automated DevOps workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Encore's framework and local development tools are free and open source. Encore Cloud offers a free tier with two development environments and 1 million tracing events per month, suitable for hobby projects.$q$, $q$The Pro tier starts at $49 per member per month plus $99 per month per deployed cloud environment and roughly $2.50 per month per resource, adding preview environments, custom domains, and integrations. An Enterprise tier with custom SLAs and compliance support is available at custom pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d5d1f6f-0d6c-43a6-848d-b04582cb94c5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Multi-format activity import$q$, $q$Imports workout activities from GPX, TCX, and FIT files used by most GPS watches and fitness devices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Strava and Garmin Connect sync$q$, $q$Directly integrates with Strava and Garmin Connect to migrate or continue syncing activity history.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Gear tracking$q$, $q$Tracks mileage and wear for equipment such as bicycles, running shoes, and wetsuits.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Multi-user support$q$, $q$Supports multiple user accounts on a single self-hosted instance for households or small clubs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Companion mobile app$q$, $q$A Flutter-based mobile app for iOS and Android connects directly to a user's self-hosted Endurain instance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Weight, sleep, and goal tracking$q$, $q$Logs body weight and sleep data alongside training goals for a broader view of athletic performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Privacy controls$q$, $q$Per-activity privacy settings let users decide what data is visible to other users on the instance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Metric and imperial units, multi-language$q$, $q$Supports both measurement systems and multiple interface languages for international users.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Completely free with full ownership of personal fitness data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Runs on inexpensive hardware such as a Raspberry Pi 4$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Dedicated mobile app gives near feature parity with commercial apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Open-source AGPL-3.0 code can be audited, modified, or extended$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Requires comfort with Docker and self-hosting to set up and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$No official cloud-hosted option; users are responsible for their own uptime and backups$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Smaller feature set and polish compared to mature commercial platforms like Strava$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Community-maintained project without formal support SLAs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Is Endurain free?$q$, $q$Yes. Endurain is completely free and open source under the AGPL-3.0 license. There are no subscription fees; users only pay for their own hosting hardware or server costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$What hardware do I need to self-host Endurain?$q$, $q$The minimum recommended hardware is a Raspberry Pi 4 with 4GB of RAM, or any x64 server with at least 2GB of RAM, with 4GB RAM and SSD storage recommended for better PostgreSQL performance.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Does Endurain have a mobile app?$q$, $q$Yes. Endurain Mobile is an official Flutter-based companion app available for both iOS and Android that connects to a self-hosted Endurain instance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Can Endurain import data from Strava?$q$, $q$Yes. Endurain supports direct integration with Strava and Garmin Connect, as well as manual import of GPX, TCX, and FIT files.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Who created Endurain?$q$, $q$Endurain was created by Portugal-based developer João Vitória Silva, initially as a personal project to gain development experience while tracking his own athletic gear.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$What license does Endurain use?$q$, $q$Endurain is licensed under the GNU Affero General Public License v3.0 (AGPL-3.0), and commercial use of the Endurain name requires separate written permission.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Privacy-first activity tracking$q$, $q$Athletes who don't want their GPS routes and training data stored on a third-party cloud service run Endurain on their own server.$q$, $q$Privacy-conscious runners and cyclists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Home lab and self-hosting projects$q$, $q$Self-hosting enthusiasts add Endurain to an existing stack of home-server applications alongside tools like Immich or Nextcloud.$q$, $q$Home-lab and self-hosting hobbyists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Multi-user club or household tracking$q$, $q$Small clubs or households run a single Endurain instance to track gear and activities for multiple members.$q$, $q$Running or cycling clubs and families$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access under AGPL-3.0","Unlimited self-hosted users","Gear, weight, sleep, and goal tracking","Strava and Garmin Connect sync","Official Docker deployment","Flutter mobile app for iOS and Android"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Endurain is a free, open-source, self-hosted fitness tracking platform built as a privacy-focused alternative to cloud services like Strava, giving athletes full control over where their activity data is stored.$q$, $q$Created by Portugal-based developer João Vitória Silva, the project began as a personal learning exercise and has grown into an actively maintained open-source tool with a dedicated Flutter mobile app for iOS and Android.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Endurain supports importing GPX, TCX, and FIT activity files, plus direct sync with Strava and Garmin Connect, alongside gear tracking for bikes and shoes, multi-user support, weight and sleep logging, and goal tracking.$q$, $q$Built on a Vue.js 3 frontend and Python FastAPI backend with PostgreSQL storage, it deploys via an official Docker image and runs comfortably on hardware as modest as a Raspberry Pi 4 with 4GB of RAM.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Endurain is entirely free and open source under the AGPL-3.0 license, with no paid tiers, subscriptions, or company behind it.$q$, $q$Users self-host the application on their own hardware, from a Raspberry Pi to a full x64 server, and only incur their own infrastructure costs; commercial use of the Endurain name requires separate written permission under its trademark policy.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ef40ba1-79b2-4345-9ec2-bc2a4731b77e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Unified marketing, sales, and service CRM$q$, $q$Combines email marketing, sales pipelines, and helpdesk ticketing in one platform with a shared contact database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Marketing automation builder$q$, $q$Visual workflow builder for automated email sequences, lead scoring, and behavior-triggered campaigns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Live chat and helpdesk$q$, $q$Built-in live chat widget and ticketing system for customer support, included even on the free plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Landing pages and web pop-ups$q$, $q$Drag-and-drop landing page builder and web pop-up forms for lead capture without additional tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$SMS marketing$q$, $q$Send SMS campaigns and automated text messages alongside email marketing from the Basic tier upward.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Native mobile apps$q$, $q$iOS and Android apps let teams manage contacts, deals, and support conversations from a phone.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$AI-assisted features$q$, $q$AI-powered email writing assistance and predictive lead scoring layered across marketing and sales tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Custom reporting and SSO$q$, $q$Pro plan adds custom reports, web and proposal analytics, and single sign-on for larger teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Genuinely free plan for up to 250 contacts, not just a time-limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Combines marketing, sales, and support in one platform at a fraction of HubSpot's cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Native iOS and Android mobile apps included$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Biennial billing discount offers substantial long-term savings$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Individual modules are generally less deep than category specialists like ActiveCampaign or Pipedrive$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Per-user pricing can add up for larger sales and marketing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Some advanced features like SSO and custom reporting are gated to the top Pro tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Contact limits per plan require frequent upgrades for fast-growing lists$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Does EngageBay have a free plan?$q$, $q$Yes. EngageBay offers a permanent free plan for up to 250 contacts with no credit card required, including basic email marketing, CRM, helpdesk, and live chat.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$How much does EngageBay cost?$q$, $q$Paid plans start at $14.99/user/month for Basic, $64.99/user/month for Growth, and $119.99/user/month for Pro, with additional discounts for annual or biennial billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Who founded EngageBay?$q$, $q$EngageBay was founded in 2017 by Sreedhar Ambati and is headquartered in Wilmington, Delaware.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Is EngageBay a good HubSpot alternative?$q$, $q$EngageBay is widely marketed and reviewed as a HubSpot alternative because it bundles marketing, sales, and service tools at a significantly lower price point, though its individual modules are less advanced than HubSpot's specialized hubs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Does EngageBay have a mobile app?$q$, $q$Yes. EngageBay offers native mobile apps for both iOS and Android that support contact management, deal tracking, and live chat.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$What are EngageBay's main competitors?$q$, $q$EngageBay is most frequently compared to HubSpot, ActiveCampaign, and Zoho CRM, competing primarily on price and all-in-one feature breadth.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$All-in-one small business CRM$q$, $q$Small businesses replace separate email marketing, CRM, and helpdesk subscriptions with a single connected platform.$q$, $q$Small business owners and startup teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Affordable HubSpot alternative$q$, $q$Growing companies that outgrow free tools but find HubSpot's hub-based pricing too expensive switch to EngageBay for similar functionality at lower cost.$q$, $q$Startups and SMBs evaluating marketing/CRM platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Combined sales and support workflows$q$, $q$Sales and support teams use EngageBay's shared contact database to see deal history and support tickets in one view.$q$, $q$Sales and customer support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 250 contacts","Email marketing and autoresponders","1 landing page","Basic CRM, helpdesk, and live chat","2 lists, 5 forms, 2 email sequences max"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Basic$q$, $q$$14.99/user/month (from $12.74 biennial)$q$, $q$Monthly, Annual, or Biennial$q$, NULL, $q$["Up to 500 contacts","Email templates and web pop-ups","Landing page builder (up to 10 pages)","Lead scoring and SMS marketing","Broader integrations and social suite"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Growth$q$, $q$$64.99/user/month (from $55.24 biennial)$q$, $q$Monthly, Annual, or Biennial$q$, NULL, $q$["Up to 5,000 contacts","Marketing automation workflows","Push notifications and site messages","A/B testing on broadcasts","5GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$Pro$q$, $q$$119.99/user/month (from $101.99 biennial)$q$, $q$Monthly, Annual, or Biennial$q$, NULL, $q$["Up to 50,000 contacts","Web and proposal analytics","Single sign-on (SSO)","Custom reporting and dedicated account manager","20GB storage, 750K API calls/month"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$EngageBay is an all-in-one CRM platform combining marketing automation, sales pipeline management, and a customer support helpdesk into a single connected system, positioned as an affordable alternative to enterprise suites like HubSpot for small and growing businesses.$q$, $q$Founded in 2017 by Sreedhar Ambati and headquartered in Wilmington, Delaware, EngageBay has grown as a largely bootstrapped company and is frequently reviewed and marketed specifically as a lower-cost HubSpot alternative.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is organized into a Marketing Bay (email campaigns, automation, landing pages, lead scoring), a CRM & Sales Bay (deal pipelines, contact management, appointment scheduling), and a Service Bay (live chat, helpdesk ticketing), all sharing one contact database.$q$, $q$Native mobile apps for iOS and Android let sales and support teams manage contacts, deals, and live chat conversations on the go, and the platform increasingly layers AI-assisted email writing and predictive lead scoring across all three modules.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$EngageBay offers a permanent Free plan for up to 250 contacts with no credit card required, alongside three paid tiers: Basic from $14.99/user/month, Growth from $64.99/user/month, and Pro from $119.99/user/month, each raising contact limits and unlocking deeper automation, analytics, and support features.$q$, $q$Annual billing saves roughly 8% and biennial billing saves roughly 15% off monthly list prices across all paid tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
