INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('61f5e19c-7e36-43c9-9e96-50d55146d278', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Unified multi-channel API$q$, $q$Single API to send notifications across in-app, email, push, SMS, and WhatsApp channels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Visual workflow builder$q$, $q$Define notification logic, channel fallback order, and audience targeting without redeploying application code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Reusable templates$q$, $q$Editable, localizable notification content templates that non-technical teammates can update independently of code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Multi-tenancy support$q$, $q$Serve multiple downstream customer organizations or environments from a single Engagespot account.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$In-app notification inbox$q$, $q$Prebuilt, embeddable notification feed component for web and mobile apps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Two-way notifications$q$, $q$Supports notifications that can receive user responses, not just one-way alerts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Multi-lingual templates$q$, $q$Growth-tier support for translated notification content across multiple languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Enterprise compliance options$q$, $q$SSO/SAML, SOC 2, and HIPAA support along with private cloud or on-premises deployment for regulated industries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Generous free-forever tier covering 10,000 events per month with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Unified API removes the need to integrate each notification channel separately$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Multi-tenancy support well suited to B2B SaaS platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Enterprise tier offers HIPAA and SOC 2 compliance with private/on-prem deployment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Growth tier's $250/month starting price is a steep jump from the free plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Not open source, unlike direct competitor Novu$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Event-based overage pricing can be harder to forecast at variable notification volumes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Smaller ecosystem and community compared to more established competitors like Twilio$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$What is Engagespot used for?$q$, $q$Engagespot is a notification infrastructure platform that provides a single API for developers to send in-app, email, push, SMS, and WhatsApp notifications without integrating each channel separately.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Does Engagespot have a free plan?$q$, $q$Yes. The Launch plan is free forever for up to 10,000 notification events per month, with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$How much does Engagespot cost?$q$, $q$After the free Launch plan, the Growth plan costs $250/month for up to 250,000 events, and Enterprise starts at $2,500/month with custom, volume-based pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Who founded Engagespot?$q$, $q$Engagespot was founded by Anand Sukumaran, who previously founded the product engineering firm Logidots.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Is Engagespot open source?$q$, $q$No. Engagespot is a closed-source, hosted commercial platform, unlike its competitor Novu, which is open source and MIT-licensed.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$What are Engagespot's main competitors?$q$, $q$Engagespot competes with other notification infrastructure platforms including Knock, Novu, Courier, SuprSend, and MagicBell.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$In-app notification feeds$q$, $q$Product teams add an embeddable in-app notification inbox to their web or mobile app without building it from scratch.$q$, $q$Product and engineering teams at SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Multi-channel transactional alerts$q$, $q$Send order updates, account alerts, or reminders across email, SMS, and push from a single API call with automatic channel fallback.$q$, $q$Backend engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$B2B multi-tenant notification delivery$q$, $q$B2B SaaS platforms use multi-tenancy to send branded notifications on behalf of many separate downstream customer organizations.$q$, $q$B2B SaaS platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Launch$q$, $q$Free forever$q$, $q$Monthly$q$, NULL, $q$["Up to 10,000 events/month","Unlimited channels and workflows","Two-way notifications","US/EU region hosting","Multi-tenancy support","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Growth$q$, $q$$250/month$q$, $q$Monthly$q$, NULL, $q$["Up to 250,000 events/month (then $1.50 per additional 1,000)","Remove Engagespot branding","Multi-lingual templates and translations","Priority email and chat support","Unlimited environments"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$Enterprise$q$, $q$From $2,500/month$q$, $q$Custom$q$, NULL, $q$["Custom volume-based event pricing","Custom SLA with 24/7 priority support","Dedicated solutions architect","Data warehouse and observability integrations","SSO/SAML, SOC 2, and HIPAA compliance","Private cloud or on-premises deployment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Engagespot is a notification infrastructure platform that gives developers a single unified API to send multi-channel notifications, including in-app feeds, email, push, SMS, and WhatsApp, instead of integrating separately with each channel's provider.$q$, $q$Founded by Anand Sukumaran, who previously founded product engineering firm Logidots, Engagespot applies an 'infrastructure as an API' approach to notifications, similar to how Algolia turned search into a dedicated API layer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is built around channels, workflows, and templates, letting both engineers and non-technical teammates adjust notification logic and copy without redeploying application code, and supports multi-tenancy for B2B SaaS companies serving many downstream customers.$q$, $q$Engagespot is designed to scale to millions of notifications and billions of API requests per month, with two-way notification support and region hosting in both the US and EU.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Engagespot's Launch plan is free forever for up to 10,000 notification events per month with no credit card required, covering unlimited channels and workflows.$q$, $q$The Growth plan costs $250/month for up to 250,000 events (then $1.50 per additional 1,000), adding white-labeling and multi-lingual templates, while Enterprise starts at $2,500/month with custom SLAs, dedicated support, and compliance features like SSO/SAML, SOC 2, and HIPAA.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
