INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('128a81ea-1a14-4c1e-9cd9-5cad1207d02b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Cross-platform Node.js architecture$q$, $q$Runs on Linux, FreeBSD, OpenBSD, macOS, and Windows anywhere Node.js is supported.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Telnet, SSH, and WebSocket access$q$, $q$Supports classic terminal BBS clients as well as modern browser-based Telnet/SSH gateways.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Native DOS door game emulation$q$, $q$Runs classic x86/DOS BBS door games like Legend of the Red Dragon and TradeWars via the v86 emulator with zero external dependencies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$FidoNet-style message networking$q$, $q$Built-in FTN support with BSO import/export and a native BinkP mailer for inbound and outbound message routing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$HJSON-based customization$q$, $q$Menus, themes, and color schemes are configured through human-friendly JSON, with JavaScript mod support for deeper customization.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Full-text searchable file base$q$, $q$Gazelle-inspired file areas with full-text search, hashtags, and temporary HTTP(S) download links.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Z-Machine interactive fiction support$q$, $q$Runs classic Infocom interactive fiction titles natively within Node.js without an external emulator.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Door gaming network integrations$q$, $q$Built-in support for BBSLink, DoorParty, Exodus, and CombatNet inter-BBS door gaming networks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Completely free and open source under the permissive BSD-2-Clause license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Runs cross-platform on Linux, macOS, Windows, FreeBSD, and OpenBSD$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Native DOS door game emulation with no external emulator dependencies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Actively maintained with a deep, still-growing feature set for a niche category$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Steep learning curve for users unfamiliar with BBS culture or terminal-based interfaces$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Requires comfort with server administration and configuration files to set up$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Very small target audience compared to modern messaging or community platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Limited official documentation depth for some advanced modding features$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$What is ENiGMA½ BBS?$q$, $q$ENiGMA½ is a free, open-source Bulletin Board System (BBS) software package written in Node.js that recreates the classic dial-up BBS experience over modern Telnet, SSH, and WebSocket connections.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Who created ENiGMA½?$q$, $q$ENiGMA½ was created by Bryan Ashby, known online by the handle NuSkooler, with development beginning around October 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Is ENiGMA½ free?$q$, $q$Yes. ENiGMA½ is completely free and open source under the BSD-2-Clause license, with no pricing tiers or company behind it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Can ENiGMA½ run classic DOS door games?$q$, $q$Yes. ENiGMA½ includes native x86/DOS emulation via the v86 emulator, letting it run classic BBS door games like Legend of the Red Dragon and TradeWars with no external emulator required.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$What platforms does ENiGMA½ support?$q$, $q$ENiGMA½ runs anywhere Node.js runs, with confirmed support on Linux, FreeBSD, OpenBSD, macOS, and Windows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$How do I connect to an ENiGMA½ BBS?$q$, $q$You can connect via Telnet, SSH, or secure/non-secure WebSocket, using either traditional terminal BBS client software or a browser-based gateway like fTelnet.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Running a retro BBS community$q$, $q$Hobbyists set up their own ENiGMA½ board to host message areas, file sharing, and door games for the BBS revival community.$q$, $q$Retrocomputing and BBS hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$FidoNet-style message networking$q$, $q$Sysops connect their board to FidoNet-style networks to exchange messages with other BBS systems worldwide.$q$, $q$BBS sysops and FidoNet network participants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Classic door game preservation$q$, $q$Retro gaming enthusiasts use ENiGMA½'s built-in DOS emulation to preserve and play classic BBS door games without separate emulator setup.$q$, $q$Retro gaming and software preservation communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under BSD-2-Clause license","Unlimited simultaneous users","Telnet, SSH, and WebSocket access","Native DOS door game emulation","FidoNet-style (FTN) message networking","Docker, script, or manual installation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ENiGMA½ (Enigma 1/2 BBS) is a free, open-source Bulletin Board System package written entirely in Node.js, recreating the classic dial-up BBS experience of the 1980s and 90s for modern Telnet, SSH, and WebSocket connections.$q$, $q$Authored by Bryan Ashby (online handle NuSkooler) starting around October 2015, the project is released under the BSD-2-Clause license and remains actively maintained by its creator alongside a community of retrocomputing and BBS hobbyist contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ENiGMA½ runs cross-platform anywhere Node.js runs, supports unlimited simultaneous users, and is highly customizable through HJSON-based menus, themes, and JavaScript mods, alongside native FidoNet-style (FTN) message network support with a built-in BinkP mailer.$q$, $q$Standout technical features include native x86/DOS door game emulation via the v86 emulator (running classics like Legend of the Red Dragon and TradeWars with zero external dependencies), a built-in Z-Machine interpreter for Infocom interactive fiction, and a full-text-searchable file base system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ENiGMA½ is entirely free and open source with no pricing tiers, subscriptions, or company behind it, released under the permissive BSD-2-Clause license.$q$, $q$It can be installed via an automated shell script, manual source build, or an official Docker image, and users only incur their own server hosting costs to run a board.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fcc4c746-3637-450b-9b93-e0c4703382b5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
