-- ── Enclosed ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Enclosed is a free, open-source, minimalistic web app for sending private, end-to-end encrypted, self-destructing notes and files with zero server-side knowledge of their contents.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$Independent open-source project (single primary maintainer)$q$, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Enclosed Review 2026: Secure Notes Tool & Self-Hosting$q$, seo_title),
  seo_meta_description = COALESCE($q$Enclosed review: an open-source, end-to-end encrypted app for sending private, self-destructing notes and files. See features, self-hosting, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Enclosed is a free, open-source web application for sending private and secure notes, built by French software engineer Corentin Thomasset (GitHub handle CorentinTh) and launched publicly on Product Hunt on October 27, 2024. The tool solves a narrow but common problem: people frequently need to share sensitive information, such as passwords, API keys, or personal details, through a channel that is more secure and more ephemeral than email, Slack, or a chat app, where a message can sit indefinitely in plaintext and be read by anyone with access to the account or the underlying infrastructure. Enclosed addresses this by letting a sender compose a note, optionally attach a file, optionally protect it with a password, and generate a one-time or time-limited link that can be shared with a recipient. Once the link is opened, or once the note's set expiration time is reached, the content is permanently deleted from the server. Technically, Enclosed is built with a SolidJS frontend and a HonoJS (Node.js/edge-compatible) backend, and its core security design is genuine end-to-end, zero-knowledge encryption: notes are encrypted entirely within the sender's browser using AES-GCM with a 256-bit key derived through PBKDF2, and the server never has access to the plaintext content or the decryption key, which typically travels in the URL fragment rather than being transmitted to or stored on the server. This zero-knowledge architecture means that even the operator of an Enclosed instance, whether that is Corentin's own hosted service at enclosed.cc or a self-hosted deployment, cannot read the notes passing through the system, which is the tool's primary differentiator from simpler pastebin-style sharing services. The project is released under the Apache License 2.0, and its source code is publicly available on GitHub at CorentinTh/enclosed, alongside a published Docker image (corentinth/enclosed on Docker Hub) that makes self-hosting straightforward for anyone who wants to run their own private instance rather than relying on the public enclosed.cc site. Documentation for configuration and self-hosting is maintained at docs.enclosed.cc. Because the project is community-maintained and not backed by a commercial company, there is no pricing model in the traditional sense: the hosted instance at enclosed.cc is free to use, and self-hosting is free aside from whatever infrastructure costs a user incurs to run the Docker container. Additional functionality includes a command-line interface for creating notes directly from a terminal, which appeals to developers who want to share secrets like environment variables or credentials without leaving their workflow, as well as cross-device support so notes can be created and read from desktop or mobile browsers alike. Enclosed's target users are developers, sysadmins, and privacy-conscious individuals who need a lightweight way to transmit one-time secrets, distinct from full password managers (like Bitwarden or 1Password, which are built for long-term secret storage) and distinct from ephemeral messaging apps (like Signal, which require both parties to have an account). Its closest competitors are other self-destructing note tools such as PrivNote, Yopass, and OneTimeSecret, all of which share the same basic model of encrypt-link-expire; Enclosed differentiates itself through its modern, minimalist interface, active open-source development, straightforward self-hosting via Docker, and a CLI tool aimed specifically at developers. As a smaller, community-driven project, Enclosed does not publish company size, funding, or headquarters information in the traditional corporate sense, and its long-term sustainability depends on continued open-source maintenance by its creator and contributors rather than a commercial business model.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b886551b-23de-40d7-8f48-7bb6d59c286b';

