-- ── Encore ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Encore is an open-source backend framework and cloud platform for TypeScript and Go that lets developers declare infrastructure as code and automatically provisions it in their own AWS or GCP account.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (framework and local dev); Encore Cloud Pro from $49/member/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small startup team$q$, company_size),
  headquarters = COALESCE($q$Stockholm, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Encore Review 2026: Backend Framework & Cloud Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Encore review: open-source TypeScript/Go backend framework with automated cloud infrastructure. Compare pricing, features, and alternatives like Supabase.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Encore is an open-source backend development framework and companion cloud platform designed to let engineers write backend services in TypeScript or Go and have infrastructure such as databases, Pub/Sub topics, cron jobs, and caches provisioned automatically, rather than manually configuring cloud resources or writing Terraform. The company was founded in Stockholm, Sweden in 2020 by André Eriksson (CEO) and Marcus Kohlberg, both of whom spent years as engineers and product leaders at Spotify before starting Encore; that background in building and scaling backend infrastructure at a large engineering organization directly informs Encore's philosophy of removing boilerplate and infrastructure toil from backend development. Encore raised a $3 million seed round led by London-based Crane Venture Partners, with participation from Acequia Capital, Essence Venture Capital, Third Kind Venture Capital, and angel investors including Kleiner Perkins partner Bucky Moore, Algolia co-founder Nicolas Dessaigne, and DeepMind product lead Mehdi Ghissassi. Technically, Encore's core idea is 'infrastructure from code': rather than writing separate infrastructure-as-code files, developers declare resources like SQL databases, Pub/Sub topics, cron jobs, and object storage buckets directly as typed objects inside their application code, and Encore's compiler and runtime parse those declarations to automatically provision matching resources, first locally for development (with a real local Postgres instance, distributed tracing, and a built-in API explorer, no cloud account required) and then in production inside the developer's own AWS or GCP account when deployed through Encore Cloud. This is a meaningfully different approach from Backend-as-a-Service platforms like Supabase or Firebase, where the platform itself hosts your database and auto-generates APIs from a schema; Encore instead has developers write full backend services in code and deploys those services, along with their declared infrastructure, into cloud accounts that customers themselves own and control, which avoids vendor lock-in since `encore build docker` can generate a standard container that runs anywhere. As of May 2024, Encore made its local development tooling fully open source, meaning the core framework, local infrastructure emulation, local distributed tracing, test tracing, and API explorer can all be used entirely for free without ever creating an Encore account; only the managed Encore Cloud platform, which handles automated cloud provisioning, preview environments, production tracing dashboards, and DevOps workflows, remains a paid, proprietary service. On pricing, Encore Cloud offers a free tier suitable for hobby projects and early development, including two free development environments, 1 million distributed tracing events per month, 7-day log and trace retention, secrets management, CI/CD, and one concurrent build, alongside community Discord support. The paid Pro tier starts at $49 per team member per month and adds unlimited free development environments, 20 million tracing events per month (with overage billed at $1.20 per additional million), 30-day log and trace retention, preview environments per pull request, custom domains, a Web Application Firewall, and integrations with Datadog and Grafana; deploying to a customer's own AWS or GCP account on the Pro tier additionally costs $99 per month per environment plus roughly $2.50 per month per provisioned resource (services, databases, cron jobs, caches, buckets, topics, and secrets). An Enterprise tier adds custom concurrent build limits, least-privilege IAM management, self-hosted preview environments, custom network security rules, custom RBAC, SOC 2 compliance assistance, a dedicated Technical Account Manager, and custom uptime SLAs, all at custom pricing. Encore's target users are backend and full-stack engineering teams, particularly at startups and growth-stage companies, who want the deploy simplicity of a PaaS like Heroku, Render, or Railway but with resources landing inside their own cloud account rather than a third party's, preserving compliance, data residency, and cost control. Its most commonly cited competitors and comparison points include Supabase and Firebase (schema-first BaaS platforms), Railway and Render (git-push PaaS platforms that host infrastructure themselves rather than in the customer's account), and infrastructure-as-code tools like Pulumi, SST, and AWS CDK, against which Encore's differentiator is combining the ergonomics of a typed application framework with automatic, code-derived infrastructure provisioning directly into a customer-owned cloud account.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3d5d1f6f-0d6c-43a6-848d-b04582cb94c5';

