-- ── Endurain ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Endurain is a free, open-source, self-hosted fitness activity tracking platform that gives athletes full ownership of their workout data as a privacy-focused alternative to Strava.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Independent open-source project (community-maintained)$q$, company_size),
  headquarters = COALESCE($q$Portugal$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Endurain Review 2026: Self-Hosted Fitness Tracker Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Endurain review: an open-source, self-hosted Strava alternative for tracking activities and gear. See features, self-hosting requirements, and mobile apps.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Endurain is a free, open-source, self-hosted fitness tracking platform created by Portugal-based developer João Vitória Silva as an alternative to closed, cloud-based services like Strava for athletes who want to fully own and control their workout data. The project began as a personal learning exercise, with its creator stating the original goal was to gain development experience while building a practical tool to track personal athletic equipment usage; it has since grown into an actively maintained open-source project with its own companion mobile app and a community of self-hosting enthusiasts. Endurain's core appeal is the same one driving the broader self-hosting movement: instead of uploading GPS routes, heart rate data, pace, and personal records to a third-party cloud service that may change its terms, restrict API access, or eventually be acquired or shut down, users run Endurain on their own hardware, from a Raspberry Pi 4 with 4GB of RAM up to a full x64 server, and retain complete control over where their fitness history lives. This has become an increasingly relevant pitch after Strava tightened access to its free developer API, prompting several self-hosted alternatives, Endurain among them, to gain renewed attention as a way to keep training data portable and independent of any single vendor's policies. Technically, Endurain is built with a Vue.js 3 and TypeScript frontend styled with Tailwind CSS and shadcn-vue components, using Pinia and TanStack Query for state management, backed by a Python FastAPI application with Alembic and SQLAlchemy for the data layer and a PostgreSQL database for storage; deployment is handled through an official Docker image configured primarily through environment variables, and recommended hardware for smooth performance with PostgreSQL is 4GB of RAM with SSD storage, though the app will run on more modest hardware. Functionally, Endurain supports importing activities in the standard GPX, TCX, and FIT file formats used by most fitness devices, and it offers direct integrations with Strava and Garmin Connect so users can migrate existing activity history or continue to sync from those platforms alongside self-hosted storage. Beyond basic activity logging, Endurain includes gear tracking for equipment like bicycles, running shoes, and wetsuits so users can monitor mileage and wear per item, multi-user support so a household or small club can share one instance, weight and sleep logging, goal tracking, privacy controls per activity, support for both metric and imperial units, and multi-language localization. A dedicated Flutter-based companion mobile app, Endurain Mobile, is available for both iOS and Android and connects to a user's self-hosted instance, giving the project near feature parity with commercial fitness apps despite being entirely open source and free. The project is licensed under the GNU Affero General Public License v3.0 (AGPL-3.0), a copyleft license that requires anyone who modifies and distributes the software, including as a hosted service, to release their source code as well; Endurain's trademark policy separately requires explicit written permission for commercial use of the Endurain name or branding. There is no company behind Endurain in the traditional sense, no funding, no pricing tiers, and no employees; it is maintained as a community open-source project, distributed primarily via its GitHub organization (endurain-project) and, following a move away from GitHub for parts of its hosting, a mirror on Codeberg. Endurain's target users are privacy-conscious endurance athletes, cyclists, and runners who are comfortable running Docker containers on a home server or a small device like a Raspberry Pi, as well as broader self-hosting and home-lab enthusiasts who want to add fitness tracking to an existing stack of self-hosted apps. Its direct competitors in the self-hosted fitness space include projects like Gessi and other emerging alternatives, but its more commonly referenced comparison point is the commercial cloud incumbent Strava, alongside other fitness platforms like Garmin Connect and Wahoo, against which Endurain's key differentiators are complete data ownership, no subscription cost, and full customizability of the underlying code.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7ef40ba1-79b2-4345-9ec2-bc2a4731b77e';

